INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00250', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「有一個『雁行理論』說，當雁鼓動雙翼時，對尾隨的同伴具有『鼓舞』 的作用，雁群一字排開成V字型時，比孤雁單飛增加了七成的飛行距離。 一般來說，不論何時，當一隻雁脫離隊伍，牠馬上會感受到一股動力阻止 牠離開，藉著前一隻夥伴的『支撐力』，牠很快便能回到隊伍。此外，在 一個雁陣中，當帶頭的雁疲倦了，牠會退回隊伍，由另一隻取代牠的位置。 同時，在雁陣隊伍中後面的雁，會以叫聲鼓勵前面的夥伴繼續前進；當有 雁隻生病或受傷時，其他兩隻會由隊伍飛下來協助及保護牠，這兩隻雁便 一直陪伴牠到康復或死亡為止，然後牠們自己組成隊伍再開始飛行，或者 去追趕上原來的雁群。」根據上文「雁行理論」所帶給人們的啟示，下列 選項何者錯誤？', '["留在與自己目標一致的隊伍，並且樂意接受他人的協助，便能使團隊邁 向成功之路", "與擁有相同目標的人同行，因著彼此之間的互相推動，便能快速、容易 地到達目的地", "為避免拖累團隊達標進展，就算眼前困難重重，也要抱著捨我其誰的精 神，繼續拼搏", "適時給予團隊夥伴讚美與鼓勵，能使團隊挺過艱難的時刻、有動力持續 努力並達成目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00251', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「在我們空前焦慮自己是個沒故事、沒身世、沒歷史的——民族？島嶼？ 國家？——的此時此際，難道我們甘心注定永遠是個樹小牆新、沒有積累、 沒有記憶，因此對這個地方也沒有什麼不可讓渡的感情的民族？島嶼？國 家？格雷安．葛林在《哈瓦那特派員》寫過：『人口研究報告可以印出各 種統計數值、城市人口，藉以描繪一個城市。但對城裡的每個人而言，所 謂城市不過是幾條巷道、幾間房子和幾個人的組合，沒有了這些，一個城 市形同隕落，只剩下悲涼的記憶，那種痛苦就像失去了一條腿般的空虛。』 說得真好，不是嗎？」根據上文，下列選項何者錯誤？', '["城市的故事來自於人與環境的組合", "沒有身世的城市無法累積認同的情感", "人口研究報告可具體看出城市發展軌跡", "城市沒有自己的歷史可能使居民感到焦慮"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
