  ('disabled-23e15ae5-moex-00253', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-f162a9a1', 'sub-disabled-23e15ae5-02', NULL, 'single_choice', '對位元串10011001使用循環左移運算（circularleftshiftoperation）1次， 其結果為何？', '["00110011", "11001100", "00110010", "10011010"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "95363917b60b", "answer_pdf_sha1": "34bfdea0d41a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "1414", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00254', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-f162a9a1', 'sub-disabled-23e15ae5-02', NULL, 'single_choice', '若數字以 8 位元二的補數來表示，則(11000010) +(11111111) 的結果為', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "95363917b60b", "answer_pdf_sha1": "34bfdea0d41a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "1414", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00255', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-f162a9a1', 'sub-disabled-23e15ae5-02', NULL, 'single_choice', '2 何？', '["(193)", "(-63)", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "95363917b60b", "answer_pdf_sha1": "34bfdea0d41a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "1414", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00256', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-f162a9a1', 'sub-disabled-23e15ae5-02', NULL, 'single_choice', '10', '["溢位（overflow）", "(63) 10", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "95363917b60b", "answer_pdf_sha1": "34bfdea0d41a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "1414", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00257', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-f162a9a1', 'sub-disabled-23e15ae5-02', NULL, 'single_choice', '請用布林代數（BooleanAlgebra）化簡AB+A(B+C)+B(B+C)，其最簡 結果為何？', '["B", "0", "1", "B+AC"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "95363917b60b", "answer_pdf_sha1": "34bfdea0d41a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "1414", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00258', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-f162a9a1', 'sub-disabled-23e15ae5-02', NULL, 'single_choice', '化簡標準SOP（SumofProducts）表示式：ABCABCABCABCABC， 其最簡結果為何？', '["BAC", "B+AC", "BAC", "BAC"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "95363917b60b", "answer_pdf_sha1": "34bfdea0d41a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "1414", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00259', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-111-f162a9a1', 'sub-disabled-23e15ae5-02', NULL, 'single_choice', '鏈結串列（linkedlists）與陣列（arrays）相比，下列那一個不是鏈結串列 的優點？', '["直接存取任一個串列中的資料", "動態記憶體配置", "有效率地插入資料", "有效率地刪除資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "95363917b60b", "answer_pdf_sha1": "34bfdea0d41a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "504", "s": "1414", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
